import { SignJWT, jwtVerify } from 'jose';
import { D1Gateway } from './d1-gateway';

export interface Env {
    DB: D1Database;
    CENTRIFUGO_API_KEY: string;
    CENTRIFUGO_API_URL: string;
    TOKEN_SECRET: string;
    UPSTASH_REDIS_REST_URL: string;
    UPSTASH_REDIS_REST_TOKEN: string;
    CLOUDFLARE_ACCOUNT_ID: string;
    CLOUDFLARE_API_TOKEN: string;
    PROJECT_CACHE: KVNamespace;
}

interface DocumentRequest {
    data: any;
    userId: string;
    path?: string;
    workspaceId?: string;
}

// Helper to publish to Centrifugo via fetch
async function publishToCentrifugo(env: Env, channel: string, data: any) {
    if (!env.CENTRIFUGO_API_URL || !env.CENTRIFUGO_API_KEY) {
        console.error("Centrifugo API URL or KEY missing in env");
        return;
    }


    try {
        const response = await fetch(env.CENTRIFUGO_API_URL, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `apikey ${env.CENTRIFUGO_API_KEY} `
            },
            body: JSON.stringify({
                method: 'publish',
                params: { channel, data }
            })
        });

        if (!response.ok) {
            const errorText = await response.text();
            console.error(`❌ Centrifugo publish failed(${response.status}): ${errorText} `);
        } else {
            const result = await response.json() as any;
            if (result.error) {
                console.error(`❌ Centrifugo API error: `, result.error);
            } else {
                console.log(`✅ Centrifugo publish success!`);
            }
        }
    } catch (e: any) {
        console.error("❌ Failed to publish to Centrifugo:", e.message);
    }
}

// Upstash Redis Cache Helper
class RedisCache {
    constructor(private env: Env) { }

    async get(key: string): Promise<any | null> {
        if (!this.env.UPSTASH_REDIS_REST_URL) {
            console.error('Redis Error: UPSTASH_REDIS_REST_URL is missing');
            return null;
        }
        try {
            const response = await fetch(
                `${this.env.UPSTASH_REDIS_REST_URL}/get/${encodeURIComponent(key)}`,
                {
                    headers: {
                        Authorization: `Bearer ${this.env.UPSTASH_REDIS_REST_TOKEN}`
                    }
                }
            );
            if (!response.ok) {
                console.error(`Redis GET Failed: ${response.status} ${await response.text()}`);
                return null;
            }
            const data = await response.json() as any;
            return data.result ? JSON.parse(data.result) : null;
        } catch (e) {
            console.warn('Redis GET exception:', e);
            return null;
        }
    }

    async set(key: string, value: any, ttlSeconds: number = 300): Promise<void> {
        try {
            const response = await fetch(
                `${this.env.UPSTASH_REDIS_REST_URL}/setex/${encodeURIComponent(key)}/${ttlSeconds}`,
                {
                    method: 'POST',
                    headers: {
                        Authorization: `Bearer ${this.env.UPSTASH_REDIS_REST_TOKEN}`,
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify(value)
                }
            );
        } catch (e) {
            // Silently fail cache writes to prioritize availability
        }
    }

    async del(key: string): Promise<void> {
        try {
            await fetch(
                `${this.env.UPSTASH_REDIS_REST_URL}/del/${encodeURIComponent(key)}`,
                {
                    headers: {
                        Authorization: `Bearer ${this.env.UPSTASH_REDIS_REST_TOKEN}`
                    }
                }
            );
        } catch (e) {
            console.warn('Redis DEL failed:', e);
        }
    }
}


// Security Rules Engine
class SecurityRules {
    private rules: any[];

    constructor(rulesConfig: any) {
        this.rules = rulesConfig.rules;
    }

    async evaluate(path: string, operation: 'read' | 'write' | 'delete', auth: any): Promise<boolean> {
        for (const rule of this.rules) {
            const match = this.matchPath(rule.path, path);
            if (match) {
                const expression = rule.allow[operation] || rule.allow['write'] || 'false';
                return this.evaluateExpression(expression, { ...match.params, auth });
            }
        }
        return false; // Default deny
    }

    private matchPath(pattern: string, path: string): { params: any } | null {
        const patternParts = pattern.split('/');
        const pathParts = path.split('/');

        if (pattern.endsWith('/**')) {
            const basePattern = pattern.slice(0, -3);
            if (path.startsWith(basePattern)) {
                return { params: {} }; // Basic wildcard match
            }
        }

        if (pattern.includes('{path=**}')) {
            const basePattern = pattern.split('{path=**}')[0];
            if (path.startsWith(basePattern)) {
                const remainingPath = path.substring(basePattern.length);
                return { params: { path: remainingPath } };
            }
        }

        if (patternParts.length !== pathParts.length) return null;

        const params: any = {};
        for (let i = 0; i < patternParts.length; i++) {
            if (patternParts[i].startsWith('{') && patternParts[i].endsWith('}')) {
                const paramName = patternParts[i].slice(1, -1);
                params[paramName] = pathParts[i];
            } else if (patternParts[i] !== pathParts[i]) {
                return null;
            }
        }
        return { params };
    }

    private evaluateExpression(expression: string, context: any): boolean {
        if (expression === 'true') return true;
        if (expression === 'false') return false;
        if (expression === 'auth !== null') return context.auth !== null;

        // Simple but dangerous: string comparison for auth.userId
        // In a real system, we'd use a safe expression evaluator
        try {
            // Replace variables from context
            let evalStr = expression;
            for (const [key, value] of Object.entries(context)) {
                if (typeof value === 'string') {
                    evalStr = evalStr.replace(new RegExp(key, 'g'), `'${value}'`);
                }
            }
            // For nested auth.userId
            if (context.auth) {
                evalStr = evalStr.replace(/auth\.userId/g, `'${context.auth.userId}'`);
                evalStr = evalStr.replace(/auth\.sub/g, `'${context.auth.userId}'`); // Use userId for sub
                evalStr = evalStr.replace(/auth\.role/g, `'${context.auth.role || ''}'`); // Add role if available
            }

            // Note: This is an extremely simplified evaluator for the demo
            return eval(evalStr);
        } catch (e) {
            console.error("Rule Evaluation Error:", e);
            return false;
        }
    }
}

const rulesConfig = {
    "rules": [
        {
            "path": "sync",
            "allow": {
                "read": "auth !== null"
            }
        },
        {
            "path": "storage/users/{userId}/**",
            "allow": {
                "read": "auth !== null && auth.sub === userId",
                "write": "auth !== null && auth.sub === userId",
                "delete": "auth !== null && auth.sub === userId"
            }
        },
        {
            "path": "{collection}",
            "allow": {
                "read": "true",
                "write": "auth !== null"
            }
        },
        {
            "path": "{collection}/{id}",
            "allow": {
                "read": "true",
                "write": "auth !== null"
            }
        },
        {
            "path": "{collection}/{id}/**",
            "allow": {
                "read": "true",
                "write": "auth !== null"
            }
        }
    ]
};

const security = new SecurityRules(rulesConfig);

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET, HEAD, POST, PUT, PATCH, DELETE, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization, X-Requested-With, workspaceId, X-Telestack-API-Key',
    'Access-Control-Expose-Headers': 'X-Cache, X-Redis-Key, ETag, X-Internal-Latency, X-Isolation, X-Debug-Engine-Version',
    'Access-Control-Max-Age': '86400',
    'X-Debug-Engine-Version': '3.2-Proof'
};

async function initDatabase(env: Env) {
    await env.DB.batch([
        // Platform Identity (v3.0)
        env.DB.prepare(`CREATE TABLE IF NOT EXISTS platform_users (
            id TEXT PRIMARY KEY,
            email TEXT UNIQUE NOT NULL,
            password_hash TEXT NOT NULL,
            full_name TEXT,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        )`),
        env.DB.prepare(`CREATE TABLE IF NOT EXISTS projects (
            id TEXT PRIMARY KEY,
            owner_id TEXT NOT NULL,
            name TEXT NOT NULL,
            d1_database_id TEXT,
            isolation_type TEXT DEFAULT 'physical', -- 'physical' or 'logical'
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY(owner_id) REFERENCES platform_users(id) ON DELETE CASCADE
        )`),
        env.DB.prepare(`CREATE TABLE IF NOT EXISTS api_keys (
            id TEXT PRIMARY KEY,
            project_id TEXT NOT NULL,
            key_secret TEXT UNIQUE NOT NULL,
            key_type TEXT CHECK(key_type IN ('admin', 'public')) DEFAULT 'public',
            name TEXT,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY(project_id) REFERENCES projects(id) ON DELETE CASCADE
        )`),
        env.DB.prepare(`CREATE INDEX IF NOT EXISTS idx_projects_owner ON projects(owner_id)`),
        env.DB.prepare(`CREATE INDEX IF NOT EXISTS idx_api_keys_secret ON api_keys(key_secret)`),

        // Core Data Layer
        env.DB.prepare(`
            CREATE TABLE IF NOT EXISTS documents(
                path TEXT NOT NULL,
                id TEXT NOT NULL,
                workspace_id TEXT NOT NULL,
                collection_name TEXT NOT NULL,
                parent_path TEXT NOT NULL DEFAULT "",
                depth INTEGER NOT NULL DEFAULT 0,
                user_id TEXT NOT NULL,
                data TEXT NOT NULL,
                version INTEGER DEFAULT 0,
                deleted_at DATETIME DEFAULT NULL,
                created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                PRIMARY KEY (workspace_id, path)
            )
        `),
        env.DB.prepare(`
            CREATE TABLE IF NOT EXISTS events(
                version INTEGER PRIMARY KEY AUTOINCREMENT,
                id TEXT NOT NULL,
                doc_id TEXT NOT NULL,
                workspace_id TEXT NOT NULL,
                event_type TEXT NOT NULL,
                payload TEXT NOT NULL,
                created_at DATETIME DEFAULT CURRENT_TIMESTAMP
            )
        `),
        env.DB.prepare(`CREATE INDEX IF NOT EXISTS idx_events_workspace ON events(workspace_id)`),
        env.DB.prepare(`CREATE INDEX IF NOT EXISTS idx_doc_workspace ON documents(workspace_id)`),
        env.DB.prepare(`CREATE INDEX IF NOT EXISTS idx_doc_collection ON documents(collection_name)`),
        // Covering Index: Includes workspace, hierarchy, and data for index-only scans
        env.DB.prepare(`
            CREATE INDEX IF NOT EXISTS idx_docs_covering ON documents(
                workspace_id, parent_path, depth, collection_name, path, data
            ) WHERE deleted_at IS NULL
        `)
    ]);
}

export default {
    async fetch(request: Request, env: Env, ctx: ExecutionContext): Promise<Response> {
        // Handle CORS Preflight
        if (request.method === 'OPTIONS') {
            return new Response(null, { headers: corsHeaders });
        }

        const gateway = new D1Gateway(env);
        const url = new URL(request.url);
        const method = request.method;
        const pathParts = url.pathname.split('/').filter(Boolean);

        try {
            // Initialize System DB (Platform Metadata)
            await initDatabase(env);
        } catch (e) {
            console.error("System DB Init Error:", e);
            // Continue, might be already initialized
        }

        // Extract Auth Context from JWT
        let auth: any = null;
        let workspaceId: string | null = null;
        let d1DatabaseId: string | null = null; // For Physical Isolation

        const authHeader = request.headers.get('Authorization');
        let token = authHeader && authHeader.startsWith('Bearer ') ? authHeader.split(' ')[1] : null;
        const apiKey = request.headers.get('X-Telestack-API-Key');

        if (apiKey) {
            // API Key Authentication (v3.0)
            // 1. Look up key
            const keyRecord = await env.DB.prepare("SELECT project_id, key_type FROM api_keys WHERE key_secret = ?").bind(apiKey).first() as any;
            if (keyRecord) {
                workspaceId = keyRecord.project_id as string;
                auth = { userId: 'api_client', workspaceId: workspaceId, role: keyRecord.key_type as string };

                // 2. Resolve Physical Database ID for this Project
                // Try Cache First
                d1DatabaseId = await env.PROJECT_CACHE.get(`project:${workspaceId}:db`);

                if (!d1DatabaseId) {
                    // Fallback to DB Lookup
                    const project = await env.DB.prepare("SELECT d1_database_id FROM projects WHERE id = ?").bind(workspaceId).first() as any;
                    if (project && project.d1_database_id) {
                        d1DatabaseId = project.d1_database_id;
                        // Cache for 24h
                        const dbIdValue = d1DatabaseId as string;
                        ctx.waitUntil(env.PROJECT_CACHE.put(`project:${workspaceId}:db`, dbIdValue, { expirationTtl: 86400 }));
                    }
                }
            } else {
                return new Response("Invalid API Key", { status: 401, headers: corsHeaders });
            }
        } else if (token) {
            try {
                const secret = env.TOKEN_SECRET || 'my_32_char_secret_key_testing_123';
                const secretKey = new TextEncoder().encode(secret);
                const { payload } = await jwtVerify(token, secretKey);
                auth = {
                    userId: payload.sub || payload.userId, // Support both standard and custom claims
                    workspaceId: payload.workspaceId,
                    role: payload.role // Critical: Extract role for platform actions
                };
                if (auth.workspaceId) workspaceId = auth.workspaceId;
            } catch (e) {
                console.warn("JWT Verification failed, proceeding as anonymous");
                return new Response("Invalid Token", { status: 401, headers: corsHeaders });
            }
        }



        // --- Platform Identity Routes (v3.0) ---

        // 1. Platform Signup
        if (url.pathname === '/platform/auth/signup' && method === 'POST') {
            const { email, password, fullName } = await request.json() as any;
            if (!email || !password) return new Response("Email and password required", { status: 400, headers: corsHeaders });

            const userId = crypto.randomUUID();
            // In a real production app, use proper hashing (PBKDF2/Bcrypt)
            const passwordHash = password;

            try {
                await env.DB.prepare("INSERT INTO platform_users (id, email, password_hash, full_name) VALUES (?, ?, ?, ?)").bind(userId, email, passwordHash, fullName).run();

                // Auto-login
                const token = await new SignJWT({ userId, role: 'platform_user' })
                    .setProtectedHeader({ alg: 'HS256' })
                    .setExpirationTime('24h')
                    .sign(new TextEncoder().encode(env.TOKEN_SECRET));

                return Response.json({ token, user: { id: userId, email, fullName } }, { headers: corsHeaders });
            } catch (e: any) {
                return Response.json({ error: "Signup Failed", message: e.message }, { status: 400, headers: corsHeaders });
            }
        }

        // 2. Platform Login
        if (url.pathname === '/platform/auth/login' && method === 'POST') {
            const { email, password } = await request.json() as any;

            const user = await env.DB.prepare("SELECT * FROM platform_users WHERE email = ?").bind(email).first() as any;
            if (!user || user.password_hash !== password) {
                return Response.json({ error: "Invalid Credentials" }, { status: 401, headers: corsHeaders });
            }

            const token = await new SignJWT({ userId: user.id, role: 'platform_user' })
                .setProtectedHeader({ alg: 'HS256' })
                .setExpirationTime('24h')
                .sign(new TextEncoder().encode(env.TOKEN_SECRET));

            return Response.json({ token, user: { id: user.id, email: user.email, fullName: user.full_name } }, { headers: corsHeaders });
        }

        // 2.5 Health Check (for debugging env vars)
        if (url.pathname === '/platform/health' && method === 'GET') {
            return Response.json({
                redisUrl: !!env.UPSTASH_REDIS_REST_URL,
                redisToken: !!env.UPSTASH_REDIS_REST_TOKEN,
                db: !!env.DB,
                kv: !!env.PROJECT_CACHE
            }, { headers: corsHeaders });
        }

        // 3. Create Project (with D1 Provisioning)
        if (url.pathname === '/platform/projects' && method === 'POST') {
            if (!auth || auth.role !== 'platform_user') return new Response("Unauthorized", { status: 401, headers: corsHeaders });
            const { name, isolationType = 'physical' } = await request.json() as any;

            const projectId = crypto.randomUUID();
            const apiKeyId = crypto.randomUUID();
            const keySecret = 'sk_live_' + crypto.randomUUID().replace(/-/g, '');

            try {
                let d1Id = 'native';
                if (isolationType === 'physical') {
                    console.log(`[Project Creation] Step 1: Creating Physical D1 Database for project ${projectId}`);
                    d1Id = await gateway.createDatabase(projectId);
                    console.log(`[Project Creation] Step 1 Complete: D1 ID = ${d1Id}`);

                    console.log(`[Project Creation] Step 2: Initializing Schema on Remote D1`);
                    await gateway.initializeDatabase(d1Id);
                    console.log(`[Project Creation] Step 2 Complete`);
                } else {
                    console.log(`[Project Creation] Initializing Logical Isolation for project ${projectId}`);
                    // Native schema is pre-initialized by initDatabase(env)
                }

                console.log(`[Project Creation] Step 3: Storing Metadata in System DB`);
                await env.DB.batch([
                    env.DB.prepare("INSERT INTO projects (id, owner_id, name, d1_database_id, isolation_type) VALUES (?, ?, ?, ?, ?)").bind(projectId, auth.userId, name, d1Id, isolationType),
                    env.DB.prepare("INSERT INTO api_keys (id, project_id, key_secret, key_type) VALUES (?, ?, ?, 'public')").bind(apiKeyId, projectId, keySecret)
                ]);

                console.log(`[Project Creation] Step 4: Caching Mapping`);
                ctx.waitUntil(env.PROJECT_CACHE.put(`project:${projectId}:db`, d1Id, { expirationTtl: 86400 }));

                return Response.json({ id: projectId, name, apiKey: keySecret, d1DatabaseId: d1Id, isolationType }, { headers: corsHeaders });
            } catch (e: any) {
                console.error(`[Project Creation] FAILED:`, e);
                return Response.json({ error: "Project Creation Failed", message: e.message }, { status: 500, headers: corsHeaders });
            }
        }
        // --- End Platform Routes ---


        // Routing: /documents
        if (pathParts[0] === 'documents') {
            // Unified Path Parser for arbitrary depth
            // e.g. /documents/users/u1/logs/l1
            // pathParts = ["documents", "users", "u1", "logs", "l1"]
            // collectionSegments = ["users", "u1", "logs"]
            // docId = "l1"
            // collection = "logs"
            // docPath = "users/u1/logs/l1"

            const dataSegments = pathParts.slice(1);
            const isDocOperation = dataSegments.length > 0 && dataSegments.length % 2 === 0;
            const isCollectionOperation = dataSegments.length > 0 && dataSegments.length % 2 !== 0;

            const docPath = dataSegments.join('/');
            const collection = isDocOperation ? dataSegments[dataSegments.length - 2] : dataSegments[dataSegments.length - 1];
            const docId = isDocOperation ? dataSegments[dataSegments.length - 1] : null;
            const parentPath = isDocOperation ? dataSegments.slice(0, -2).join('/') : dataSegments.slice(0, -1).join('/');
            const depth = dataSegments.length;

            const workspace = auth?.workspaceId || request.headers.get('workspaceId') || 'default';
            let resolvedDbId = await env.PROJECT_CACHE.get(`project:${workspace}:db`);
            if (!resolvedDbId) {
                const project = await env.DB.prepare("SELECT d1_database_id FROM projects WHERE id = ?").bind(workspace).first() as any;
                if (project) {
                    resolvedDbId = project.d1_database_id as string;
                    ctx.waitUntil(env.PROJECT_CACHE.put(`project:${workspace}:db`, resolvedDbId, { expirationTtl: 86400 }));
                }
            }
            const gateway = new D1Gateway(env);

            // 1. Discovery Endpoints
            if (collection === 'internal' && docId === 'collections' && method === 'GET') {
                const { results } = await env.DB.prepare(
                    "SELECT DISTINCT collection_name FROM documents WHERE workspace_id = ? AND parent_path = '' AND depth = 2 AND deleted_at IS NULL"
                ).bind(workspace).all();
                return Response.json(results.map((r: any) => r.collection_name), { headers: corsHeaders });
            }

            if (collection === 'internal' && docId === 'subcollections' && method === 'GET') {
                const parentPathSearch = url.searchParams.get('parentPath');
                if (!parentPathSearch) return new Response("parentPath required", { status: 400, headers: corsHeaders });
                const parentSegments = parentPathSearch.split('/').filter(Boolean).length;
                const targetDepth = parentSegments + 2;
                const { results } = await env.DB.prepare(
                    "SELECT DISTINCT collection_name FROM documents WHERE workspace_id = ? AND parent_path = ? AND depth = ? AND deleted_at IS NULL"
                ).bind(workspace, parentPathSearch, targetDepth).all();
                return Response.json(results.map((r: any) => r.collection_name), { headers: corsHeaders });
            }

            // Internal Reset Endpoint
            if (collection === 'internal' && docId === 'reset' && method === 'POST') {
                await env.DB.batch([
                    env.DB.prepare("DROP TABLE IF EXISTS documents"),
                    env.DB.prepare("DROP TABLE IF EXISTS events"),
                    env.DB.prepare("DROP TABLE IF EXISTS projects"),
                    env.DB.prepare("DROP TABLE IF EXISTS api_keys"),
                    env.DB.prepare("DROP TABLE IF EXISTS platform_users")
                ]);
                await initDatabase(env);
                return Response.json({ message: "Full Platform Reset Successful" }, { headers: corsHeaders });
            }

            // 0. BATCH
            if (method === 'POST' && collection === 'batch') {
                const { operations } = await request.json() as any;
                if (!Array.isArray(operations)) return new Response("operations array required", { status: 400, headers: corsHeaders });

                const gatewayOps: { sql: string, params: any[] }[] = [];
                const publishPayloads: { channel: string, data: any }[] = [];
                const workspaceId = workspace;
                const dbId = resolvedDbId || 'native';

                for (const op of operations) {
                    const { type, path, data, expectedVersion } = op;
                    const parts = path.split('/');
                    const col = parts[parts.length - 2];
                    const id = parts[parts.length - 1];
                    const userId = auth?.userId || 'anonymous';

                    const currentDoc = await gateway.query(dbId as string, "SELECT version FROM documents WHERE id = ?", [id]);
                    if (expectedVersion !== undefined) {
                        if (!currentDoc || (currentDoc.results[0] as any)?.version !== expectedVersion) {
                            return new Response(`Version Conflict for ${path}`, { status: 409, headers: corsHeaders });
                        }
                    }

                    if (!(await security.evaluate(path, type === 'DELETE' ? 'delete' : 'write', auth))) {
                        return new Response(`Permission Denied for ${path}`, { status: 403, headers: corsHeaders });
                    }

                    const eventId = crypto.randomUUID();
                    const eventType = type === 'SET' ? 'INSERT' : type === 'UPDATE' ? 'UPDATE' : 'DELETE';

                    gatewayOps.push({
                        sql: `INSERT INTO events(version, id, doc_id, workspace_id, event_type, payload) VALUES(NULL, ?, ?, ?, ?, ?)`,
                        params: [eventId, id, workspaceId, eventType, JSON.stringify(data || {})]
                    });

                    const batchParentPath = path.split('/').slice(0, -2).join('/');
                    const batchDepth = path.split('/').length;

                    if (type === 'SET') {
                        gatewayOps.push({
                            sql: `INSERT INTO documents(id, workspace_id, collection_name, path, parent_path, depth, user_id, data, version)
                                  VALUES(?, ?, ?, ?, ?, ?, ?, ?, 0)
                                  ON CONFLICT(path) DO UPDATE SET data = excluded.data, version = version + 1, updated_at = CURRENT_TIMESTAMP, deleted_at = NULL`,
                            params: [id, workspaceId, col, path, batchParentPath, batchDepth, userId, JSON.stringify(data)]
                        });
                    } else if (type === 'UPDATE') {
                        gatewayOps.push({
                            sql: `UPDATE documents SET data = json_patch(data, ?), version = version + 1, updated_at = CURRENT_TIMESTAMP WHERE id = ?`,
                            params: [JSON.stringify(data), id]
                        });
                    } else if (type === 'DELETE') {
                        gatewayOps.push({
                            sql: `UPDATE documents SET deleted_at = CURRENT_TIMESTAMP, version = version + 1 WHERE id = ?`,
                            params: [id]
                        });
                    }

                    const collectionPath = path.split('/').slice(0, -1).join('/');
                    const pubType = type === 'DELETE' ? 'DELETED' : (type === 'SET' ? 'CREATED' : 'UPDATED');
                    publishPayloads.push({
                        channel: `collection:${collectionPath.replace(/\//g, '_')}`,
                        data: { type: pubType, id, path, doc: { id, path, data, userId } }
                    });
                }

                try {
                    await gateway.batch(dbId as string, gatewayOps);
                    for (const pub of publishPayloads) {
                        await publishToCentrifugo(env, `_ws_${workspaceId}_${pub.channel}`, pub.data);
                    }
                    return Response.json({ success: true }, { headers: corsHeaders });
                } catch (error: any) {
                    return new Response(error.message, { status: 500, headers: corsHeaders });
                }
            }

            // AUTH
            else if (collection === 'auth' && docId === 'token' && method === 'POST') {
                const { userId } = await request.json() as any;
                const workspaceId = request.headers.get('workspaceId') || 'default';
                if (!userId) return new Response("userId required", { status: 400, headers: corsHeaders });

                const secret = env.TOKEN_SECRET || 'my_32_char_secret_key_testing_123';
                const token = await new SignJWT({ sub: userId, user: userId, workspaceId, pub: true })
                    .setProtectedHeader({ alg: 'HS256', typ: 'JWT' })
                    .setIssuedAt()
                    .setExpirationTime('24h')
                    .sign(new TextEncoder().encode(secret));
                return Response.json({ token }, { headers: corsHeaders });
            }

            // 1. CREATE
            else if (method === 'POST') {
                const { data, userId } = await request.json() as any;
                const dbId = resolvedDbId || 'native';
                const id = crypto.randomUUID();
                const fullDocPath = `${collection}/${id}`;

                try {
                    const eventRes = await gateway.query(dbId as string,
                        `INSERT INTO events (version, id, doc_id, workspace_id, event_type, payload) VALUES (NULL, ?, ?, ?, 'INSERT', ?)`,
                        [crypto.randomUUID(), id, workspace, JSON.stringify(data)]);
                    const version = eventRes.meta.last_row_id;
                    await gateway.query(dbId as string,
                        `INSERT INTO documents (path, id, workspace_id, collection_name, parent_path, depth, user_id, data, version) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                        [fullDocPath, id, workspace, collection, parentPath, depth + 1, userId, JSON.stringify(data), version]);

                    const cache = new RedisCache(env);
                    ctx.waitUntil(cache.del(`coll:${workspace}:${collection}:*`));
                    const payload = { type: 'CREATED', doc: { id, path: fullDocPath, data, version } };
                    await publishToCentrifugo(env, `_ws_${workspace}_collection_${collection.replace(/\//g, '_')}`, payload);
                    return Response.json({ id, path: fullDocPath, version }, { status: 201, headers: corsHeaders });
                } catch (error: any) {
                    return new Response(error.message, { status: 500, headers: corsHeaders });
                }
            }

            // 1.5 SYNC
            else if (method === 'GET' && collection === 'sync') {
                const sinceVersion = parseInt(url.searchParams.get('since') || '0');
                const cache = new RedisCache(env);
                const cacheKey = `sync:${workspace}:${sinceVersion}`;
                const cached = await cache.get(cacheKey);
                if (cached) return Response.json(cached, { headers: { ...corsHeaders, 'X-Cache': 'HIT' } });

                const dbId = resolvedDbId || 'native';
                const res = await new D1Gateway(env).query(dbId as string, "SELECT * FROM events WHERE workspace_id = ? AND version > ? ORDER BY version ASC LIMIT 1000", [workspace, sinceVersion]);
                const data = { changes: res.results.map((r: any) => ({ ...r, payload: JSON.parse(r.payload) })), serverTime: new Date().toISOString() };
                await cache.set(cacheKey, data, 30);
                return Response.json(data, { headers: { ...corsHeaders, 'X-Cache': 'MISS' } });
            }

            // 1.7 QUERY
            else if (method === 'GET' && collection === 'query') {
                const targetPath = url.searchParams.get('path');
                const filtersJson = url.searchParams.get('filters') || '[]';
                const cacheKey = `query:${workspace}:${targetPath || 'root'}:${filtersJson}`;
                const cache = new RedisCache(env);
                const cached = await cache.get(cacheKey);
                if (cached) return Response.json(cached, { headers: { ...corsHeaders, 'X-Cache': 'HIT' } });

                const dbId = resolvedDbId || 'native';
                const res = await new D1Gateway(env).query(dbId as string, `SELECT * FROM documents WHERE workspace_id = ? AND path LIKE ?`, [workspace, targetPath ? `${targetPath}/%` : '%']);
                const responseData = res.results.map((r: any) => ({ ...r, data: JSON.parse(r.data) }));
                await cache.set(cacheKey, responseData, 60);
                return Response.json(responseData, { headers: { ...corsHeaders, 'X-Cache': 'MISS' } });
            }

            // 2. LIST
            else if (method === 'GET' && isCollectionOperation && !docId) {
                const cache = new RedisCache(env);
                const cacheKey = `coll:${workspace}:${collection}:${url.searchParams.get('parentPath') || 'root'}`;
                const cached = await cache.get(cacheKey);
                if (cached) return Response.json(cached, { headers: { ...corsHeaders, 'X-Cache': 'HIT' } });

                const dbId = resolvedDbId || 'native';
                const res = await new D1Gateway(env).query(dbId as string, "SELECT * FROM documents WHERE collection_name = ? AND workspace_id = ? AND deleted_at IS NULL", [collection, workspace]);
                const responseData = res.results.map((r: any) => ({ ...r, data: JSON.parse(r.data) }));
                await cache.set(cacheKey, responseData, 60);
                return Response.json(responseData, { headers: { ...corsHeaders, 'X-Cache': 'MISS' } });
            }

            // 3. GET SINGLE
            else if (method === 'GET' && docId) {
                const startTime = Date.now();
                const fullDocPath = `${collection}/${docId}`;
                const cache = new RedisCache(env);
                const cached = await cache.get(`doc:${workspace}:${fullDocPath}`);
                if (cached) return Response.json(cached, { headers: { ...corsHeaders, 'X-Cache': 'HIT', 'X-Internal-Latency': `${Date.now() - startTime}ms`, 'ETag': `"${cached.version}"` } });

                const dbId = resolvedDbId || 'native';
                const res = await new D1Gateway(env).query(dbId as string, "SELECT * FROM documents WHERE path = ? AND workspace_id = ? AND deleted_at IS NULL", [fullDocPath, workspace]);
                if (res.results.length === 0) return new Response("Not Found", { status: 404, headers: corsHeaders });
                const docData = { ...(res.results[0] as any), data: JSON.parse((res.results[0] as any).data) };
                await cache.set(`doc:${workspace}:${fullDocPath}`, docData, 300);
                const finalHeaders = { ...corsHeaders, 'X-Cache': 'MISS', 'X-Internal-Latency': `${Date.now() - startTime}ms`, 'X-Isolation': dbId === 'native' ? 'Logical' : 'Physical', 'ETag': `"${docData.version}"` };
                return new Response(JSON.stringify(docData), {
                    status: 200,
                    headers: finalHeaders
                });
            }

            // 4. PUT
            else if (method === 'PUT' && docId) {
                const { data, userId } = await request.json() as any;
                const dbId = resolvedDbId || 'native';
                const eventId = crypto.randomUUID();
                const eventRes = await gateway.query(dbId as string, `INSERT INTO events (version, id, doc_id, workspace_id, event_type, payload) VALUES (NULL, ?, ?, ?, 'SET', ?)`, [eventId, docId, workspace, JSON.stringify(data)]);
                const version = eventRes.meta.last_row_id;
                await gateway.query(dbId as string, `INSERT INTO documents (path, id, workspace_id, collection_name, data, version) VALUES (?, ?, ?, ?, ?, ?) ON CONFLICT(path) DO UPDATE SET data = excluded.data, version = excluded.version, updated_at = CURRENT_TIMESTAMP, deleted_at = NULL`, [`${collection}/${docId}`, docId, workspace, collection, JSON.stringify(data), version]);
                return Response.json({ success: true, version }, { headers: corsHeaders });
            }

            // 6. DELETE
            else if (method === 'DELETE' && docId) {
                const dbId = resolvedDbId || 'native';
                await gateway.query(dbId as string, "UPDATE documents SET deleted_at = CURRENT_TIMESTAMP WHERE path = ? AND workspace_id = ?", [`${collection}/${docId}`, workspace]);
                return new Response(null, { status: 204, headers: corsHeaders });
            }

            return new Response("Telestack Real-time DB Engine Active", { status: 200, headers: corsHeaders });
        }

        return new Response("Telestack Gateway: Route Not Found", { status: 404, headers: corsHeaders });
    }
};
