
import { Env } from './index';

export class D1Gateway {
    private cache: KVNamespace;

    constructor(private env: Env) {
        this.cache = env.PROJECT_CACHE;
    }

    // 1. Create a new D1 Database dynamically
    async createDatabase(projectId: string): Promise<string> {
        // Extremely conservative naming: "db" + random 10 chars.
        // Total length ~12 chars. Lowercase alphanumeric only.
        const randomSuffix = Math.random().toString(36).substring(2, 12);
        const dbName = `db-${randomSuffix}`;

        const response = await fetch(
            `https://api.cloudflare.com/client/v4/accounts/${this.env.CLOUDFLARE_ACCOUNT_ID}/d1/database`,
            {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${this.env.CLOUDFLARE_API_TOKEN}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    name: dbName
                })
            }
        );

        if (!response.ok) {
            throw new Error(`Failed to create database: ${await response.text()}`);
        }

        const data = await response.json() as any;
        return data.result.uuid;
    }

    // 2. Execute SQL against a specific D1 Database
    async query(dbId: string, sql: string, params: any[] = []): Promise<any> {
        // Platform/Performance Tier Optimization: Use Native Bindings if dbId is 'native'
        if (dbId === 'native') {
            return this.nativeQuery(sql, params);
        }

        // Basic caching for SELECTs could go here (Redis/Upstash)
        // For now, ensuring functionality first.

        // console.log(`D1 REST Query [${dbId}]: ${sql}`, params);

        const response = await fetch(
            `https://api.cloudflare.com/client/v4/accounts/${this.env.CLOUDFLARE_ACCOUNT_ID}/d1/database/${dbId}/query`,
            {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${this.env.CLOUDFLARE_API_TOKEN}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ sql, params })
            }
        );

        if (!response.ok) {
            const errorText = await response.text();
            console.error(`D1 Query Failed: ${errorText}`);
            throw new Error(`D1 query failed: ${errorText}`);
        }

        const { result } = await response.json() as any;

        // The REST API returns an array of results (for batching)
        // We usually send one query, so we take the first result set.
        // Result format: [{ success: true, results: [], meta: {} }]

        if (result && result.length > 0) {
            return result[0]; // Return the first query result object matchin bindings
        }
        return { results: [], success: true, meta: {} };
    }

    // 2.2 Native Query (Sub-10ms Performance)
    async nativeQuery(sql: string, params: any[] = []): Promise<any> {
        try {
            const stmt = this.env.DB.prepare(sql).bind(...params);
            const { results, meta, success } = await stmt.all();
            return { results, meta, success };
        } catch (e: any) {
            console.error(`D1 Native Query Failed: ${e.message}`);
            throw e;
        }
    }

    // 2.5 Batch Execute (Sequential Client-Side)
    async batch(dbId: string, operations: { sql: string, params: any[] }[]): Promise<any[]> {
        const results = [];
        // Sequential execution to ensure ordering (and lack of multi-statement transaction support in REST)
        // Ideally this would use a bulk endpoint if available.
        for (const op of operations) {
            try {
                const res = await this.query(dbId, op.sql, op.params);
                results.push(res);
            } catch (e: any) {
                console.error(`Batch Op Failed: ${op.sql}`, e);
                throw e; // Abort batch on error (partial failure not supported in this simplistic model)
            }
        }
        return results;
    }

    // 3. Initialize Standard Schema for a new Project DB
    async initializeDatabase(dbId: string): Promise<void> {

        const schema = [
            `CREATE TABLE IF NOT EXISTS documents(
        path TEXT NOT NULL,
        id TEXT NOT NULL,
        workspace_id TEXT NOT NULL, -- Kept for compatibility, though DB is isolated
        collection_name TEXT NOT NULL,
        parent_path TEXT NOT NULL DEFAULT "",
        depth INTEGER NOT NULL DEFAULT 0,
        user_id TEXT NOT NULL,
        data TEXT NOT NULL,
        version INTEGER DEFAULT 0,
        deleted_at DATETIME DEFAULT NULL,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
        updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (path) -- Workspace ID not needed in PK for physical isolation, but path is unique
      )`,
            `CREATE TABLE IF NOT EXISTS events(
        version INTEGER PRIMARY KEY AUTOINCREMENT,
        id TEXT NOT NULL,
        doc_id TEXT NOT NULL,
        workspace_id TEXT NOT NULL, 
        event_type TEXT NOT NULL,
        payload TEXT NOT NULL,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
      )`,
            `CREATE INDEX IF NOT EXISTS idx_docs_parent ON documents(parent_path, depth)`,
            `CREATE INDEX IF NOT EXISTS idx_docs_collection ON documents(collection_name)`
        ];

        // Execute schema creation sequentially
        for (const sql of schema) {
            await this.query(dbId, sql);
        }
    }

    private hashQuery(sql: string, params: any[]): string {
        const input = sql + JSON.stringify(params);
        let hash = 0;
        for (let i = 0; i < input.length; i++) {
            hash = ((hash << 5) - hash) + input.charCodeAt(i);
            hash |= 0;
        }
        return hash.toString(36);
    }
}
